class Solution { public: string minWindow(string s, string t) { int i=0,j=0,minlen=INT_MAX,count=0; int n=s.size(); int m=t.size(); if(m>n) return ""; int mpp[128]; int startidx=-1; for(int k=0;k<m;k++){ mpp[t[k]]++; } while(j<n){ if(mpp[s[j]]>0) count++; mpp[s[j]]--; while(count==m){ if(j-i+1<minlen){ minlen=j-i+1; startidx=i; } mpp[s[i]]++; if(mpp[s[i]]>0) count--; i++; } j++; } return startidx==-1?"":s.substr(startidx,minlen); } };